import React, { useRef, useEffect, useState } from 'react';

function SignalChart({ data, tOn, tOff }) {
  const canvasRef = useRef(null);
  const containerRef = useRef(null);
  const [dims, setDims] = useState({ w: 600, h: 180 });

  // Track container size
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;
    const updateSize = () => {
      const rect = container.getBoundingClientRect();
      if (rect.width > 0) {
        setDims({ w: rect.width, h: 180 });
      }
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  // Draw chart
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const dpr = window.devicePixelRatio || 1;
    const W = dims.w;
    const H = dims.h;
    canvas.width = W * dpr;
    canvas.height = H * dpr;
    const ctx = canvas.getContext('2d');
    ctx.scale(dpr, dpr);

    const PAD_L = 45;
    const PAD_R = 60;
    const PAD_T = 10;
    const PAD_B = 10;
    const plotW = W - PAD_L - PAD_R;
    const plotH = H - PAD_T - PAD_B;

    // Clear
    ctx.clearRect(0, 0, W, H);

    // Background
    ctx.fillStyle = '#fafafa';
    ctx.fillRect(PAD_L, PAD_T, plotW, plotH);

    // Compute Y range
    let yMax = 3.0;
    const values = data.map((d) => d.y);
    if (values.length > 0) {
      const maxVal = Math.max(...values);
      yMax = Math.max(maxVal * 1.2, tOn * 1.5, 2.0);
    }

    const WINDOW = 100;
    const toX = (i) => PAD_L + (i / (WINDOW - 1)) * plotW;
    const toY = (v) => PAD_T + plotH - (Math.min(v, yMax) / yMax) * plotH;

    // Grid lines
    ctx.strokeStyle = '#e8e8ec';
    ctx.lineWidth = 1;
    const yTicks = [0, yMax * 0.25, yMax * 0.5, yMax * 0.75, yMax];
    yTicks.forEach((v) => {
      const y = toY(v);
      ctx.beginPath();
      ctx.moveTo(PAD_L, y);
      ctx.lineTo(PAD_L + plotW, y);
      ctx.stroke();
    });

    // Y axis labels
    ctx.fillStyle = '#999';
    ctx.font = '11px Inter, sans-serif';
    ctx.textAlign = 'right';
    ctx.textBaseline = 'middle';
    yTicks.forEach((v) => {
      ctx.fillText(v.toFixed(1), PAD_L - 6, toY(v));
    });

    // T_ON reference line
    if (tOn <= yMax) {
      const y = toY(tOn);
      ctx.strokeStyle = '#e05555';
      ctx.lineWidth = 1.2;
      ctx.setLineDash([6, 3]);
      ctx.beginPath();
      ctx.moveTo(PAD_L, y);
      ctx.lineTo(PAD_L + plotW, y);
      ctx.stroke();
      ctx.setLineDash([]);
      ctx.fillStyle = '#e05555';
      ctx.font = '10px Inter, sans-serif';
      ctx.textAlign = 'left';
      ctx.fillText(`T_ON=${tOn}`, PAD_L + plotW + 4, y);
    }

    // T_OFF reference line
    if (tOff <= yMax) {
      const y = toY(tOff);
      ctx.strokeStyle = '#e0a030';
      ctx.lineWidth = 1;
      ctx.setLineDash([6, 3]);
      ctx.beginPath();
      ctx.moveTo(PAD_L, y);
      ctx.lineTo(PAD_L + plotW, y);
      ctx.stroke();
      ctx.setLineDash([]);
      ctx.fillStyle = '#e0a030';
      ctx.font = '10px Inter, sans-serif';
      ctx.textAlign = 'left';
      ctx.fillText(`T_OFF=${tOff}`, PAD_L + plotW + 4, y);
    }

    // Signal line
    if (values.length > 1) {
      ctx.strokeStyle = '#5b6abf';
      ctx.lineWidth = 2;
      ctx.lineJoin = 'round';
      ctx.lineCap = 'round';
      ctx.beginPath();
      // Pad from the right: if < WINDOW points, start drawing from the right edge
      const offset = WINDOW - values.length;
      values.forEach((v, i) => {
        const x = toX(offset + i);
        const y = toY(v);
        if (i === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
      });
      ctx.stroke();
    }

    // Border
    ctx.strokeStyle = '#ddd';
    ctx.lineWidth = 1;
    ctx.setLineDash([]);
    ctx.strokeRect(PAD_L, PAD_T, plotW, plotH);
  }, [data, tOn, tOff, dims]);

  return (
    <div className="card signal-card">
      <h3>Activation Signal</h3>
      <div ref={containerRef} style={{ width: '100%' }}>
        <canvas
          ref={canvasRef}
          style={{ width: `${dims.w}px`, height: `${dims.h}px`, display: 'block' }}
        />
      </div>
    </div>
  );
}

export default SignalChart;
